import{_ as a,c as d,o as e,a7 as r}from"./chunks/framework.BQb8NfN9.js";const c=JSON.parse('{"title":"感知机","description":"","frontmatter":{},"headers":[],"relativePath":"ai/深度学习/感知机.md","filePath":"ai/深度学习/感知机.md","lastUpdated":1773670517000}'),s={name:"ai/深度学习/感知机.md"};function n(l,t,o,i,p,h){return e(),d("div",null,t[0]||(t[0]=[r(`<h1 id="感知机" tabindex="-1">感知机 <a class="header-anchor" href="#感知机" aria-label="Permalink to &quot;感知机&quot;">​</a></h1><p>感知机（Perceptron）是神经网络最基础的组成单元，由 Frank Rosenblatt 于 1958 年提出，是现代深度学习的起源。</p><p><strong>文档结构：</strong> 感知机定义 → 单层感知机数学模型 → 学习规则 → 局限性（XOR 问题）→ 多层感知机 → 从感知机到全连接网络。</p><hr><h2 id="一、感知机是什么" tabindex="-1">一、感知机是什么 <a class="header-anchor" href="#一、感知机是什么" aria-label="Permalink to &quot;一、感知机是什么&quot;">​</a></h2><p>感知机模仿生物神经元：接收多个输入信号，加权求和后经激活函数处理，输出一个信号（0 或 1）。</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>x1 ─── w1 ──┐</span></span>
<span class="line"><span>x2 ─── w2 ──┤  Σ → 激活函数 → y</span></span>
<span class="line"><span>x3 ─── w3 ──┘</span></span>
<span class="line"><span>       +b (偏置)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p><strong>核心要素：</strong></p><table tabindex="0"><thead><tr><th>符号</th><th>含义</th></tr></thead><tbody><tr><td>$x_i$</td><td>第 $i$ 个输入特征</td></tr><tr><td>$w_i$</td><td>对应输入的权重</td></tr><tr><td>$b$</td><td>偏置（bias），控制激活阈值</td></tr><tr><td>$y$</td><td>输出（0 或 1）</td></tr></tbody></table><hr><h2 id="二、单层感知机数学模型" tabindex="-1">二、单层感知机数学模型 <a class="header-anchor" href="#二、单层感知机数学模型" aria-label="Permalink to &quot;二、单层感知机数学模型&quot;">​</a></h2><p><strong>线性加权求和：</strong></p><p>$$z = \\sum_{i=1}^{n} w_i x_i + b = \\boldsymbol{w}^{\\top}\\boldsymbol{x} + b$$</p><p><strong>激活函数（阶跃函数）：</strong></p><p>$$y = f(z) = \\begin{cases} 1 &amp; z \\geq 0 \\ 0 &amp; z &lt; 0 \\end{cases}$$</p><p>或使用符号函数（输出 ±1）：</p><p>$$y = \\text{sign}(z) = \\begin{cases} +1 &amp; z \\geq 0 \\ -1 &amp; z &lt; 0 \\end{cases}$$</p><p><strong>几何意义：</strong> 权重向量 $\\boldsymbol{w}$ 定义了超平面 $\\boldsymbol{w}^{\\top}\\boldsymbol{x} + b = 0$，感知机本质上在做<strong>线性分类</strong>——用一条直线（或超平面）把两类数据分开。</p><hr><h2 id="三、感知机学习规则" tabindex="-1">三、感知机学习规则 <a class="header-anchor" href="#三、感知机学习规则" aria-label="Permalink to &quot;三、感知机学习规则&quot;">​</a></h2><p><strong>目标：</strong> 找到合适的 $\\boldsymbol{w}$ 和 $b$，使感知机能正确分类训练数据。</p><p><strong>更新规则（在线学习，逐样本更新）：</strong></p><p>$$w_i \\leftarrow w_i + \\eta \\cdot (y - \\hat{y}) \\cdot x_i$$</p><p>$$b \\leftarrow b + \\eta \\cdot (y - \\hat{y})$$</p><p>其中：</p><ul><li>$y$ 是真实标签，$\\hat{y}$ 是预测输出。</li><li>$\\eta$（学习率，通常取 0.01～0.1）控制每次更新幅度。</li><li>若预测正确（$y = \\hat{y}$），权重不变；预测错误时才更新。</li></ul><p><strong>收敛性：</strong> 若数据<strong>线性可分</strong>，感知机学习算法保证在有限步内收敛。</p><hr><h2 id="四、感知机的局限性" tabindex="-1">四、感知机的局限性 <a class="header-anchor" href="#四、感知机的局限性" aria-label="Permalink to &quot;四、感知机的局限性&quot;">​</a></h2><h3 id="只能处理线性可分问题" tabindex="-1">只能处理线性可分问题 <a class="header-anchor" href="#只能处理线性可分问题" aria-label="Permalink to &quot;只能处理线性可分问题&quot;">​</a></h3><p>感知机只能学出一条直线，因此<strong>无法解决 XOR（异或）问题</strong>：</p><table tabindex="0"><thead><tr><th>$x_1$</th><th>$x_2$</th><th>XOR</th></tr></thead><tbody><tr><td>0</td><td>0</td><td>0</td></tr><tr><td>0</td><td>1</td><td>1</td></tr><tr><td>1</td><td>0</td><td>1</td></tr><tr><td>1</td><td>1</td><td>0</td></tr></tbody></table><p>XOR 的四个点无法被一条直线分开，单层感知机对此无能为力。这一局限性在 1969 年由 Minsky 和 Papert 严格证明，直接导致了第一次&quot;AI 寒冬&quot;。</p><hr><h2 id="五、多层感知机-mlp" tabindex="-1">五、多层感知机（MLP） <a class="header-anchor" href="#五、多层感知机-mlp" aria-label="Permalink to &quot;五、多层感知机（MLP）&quot;">​</a></h2><h3 id="突破线性限制" tabindex="-1">突破线性限制 <a class="header-anchor" href="#突破线性限制" aria-label="Permalink to &quot;突破线性限制&quot;">​</a></h3><p>解决 XOR 问题的思路：增加隐藏层，引入非线性激活函数。</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>输入层      隐藏层         输出层</span></span>
<span class="line"><span> x1 ─┬─── [神经元1] ───┬── y</span></span>
<span class="line"><span> x2 ─┘─── [神经元2] ───┘</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><ul><li><strong>增加层数</strong>：每多一层，网络可以学到更抽象的特征表示。</li><li><strong>非线性激活函数</strong>（如 Sigmoid、ReLU）：引入非线性，使网络能拟合任意复杂的函数。</li></ul><h3 id="万能近似定理" tabindex="-1">万能近似定理 <a class="header-anchor" href="#万能近似定理" aria-label="Permalink to &quot;万能近似定理&quot;">​</a></h3><p>含一个隐藏层（足够多神经元）的 MLP，理论上可以以任意精度近似任意连续函数。</p><table tabindex="0"><thead><tr><th>网络深度</th><th>能力</th></tr></thead><tbody><tr><td>单层（无隐藏层）</td><td>仅线性分类</td></tr><tr><td>一个隐藏层 + 非线性</td><td>理论上可近似任意函数</td></tr><tr><td>多个隐藏层</td><td>更高效地表示复杂函数（参数更少）</td></tr></tbody></table><hr><h2 id="六、从感知机到全连接网络" tabindex="-1">六、从感知机到全连接网络 <a class="header-anchor" href="#六、从感知机到全连接网络" aria-label="Permalink to &quot;六、从感知机到全连接网络&quot;">​</a></h2><table tabindex="0"><thead><tr><th>概念</th><th>感知机</th><th>全连接神经网络</th></tr></thead><tbody><tr><td>激活函数</td><td>阶跃函数（不可导）</td><td>Sigmoid / ReLU / Tanh（可导）</td></tr><tr><td>层数</td><td>单层</td><td>多层（深度网络）</td></tr><tr><td>训练方法</td><td>感知机学习规则</td><td>反向传播 + 梯度下降</td></tr><tr><td>能处理问题</td><td>线性可分</td><td>线性 + 非线性</td></tr><tr><td>输出</td><td>二分类（0/1）</td><td>回归 / 多分类</td></tr></tbody></table><p>感知机是神经网络的基石：每个神经元本质上都是一个感知机，只是激活函数换成了可微函数，使得可以用梯度下降进行训练。</p><hr><h2 id="七、知识小结" tabindex="-1">七、知识小结 <a class="header-anchor" href="#七、知识小结" aria-label="Permalink to &quot;七、知识小结&quot;">​</a></h2><table tabindex="0"><thead><tr><th>知识点</th><th>核心内容</th><th>易混淆点</th><th>难度</th></tr></thead><tbody><tr><td>感知机定义</td><td>加权求和 + 阶跃激活，输出 0/1</td><td>感知机 vs 神经元（神经元用可微激活）</td><td>⭐</td></tr><tr><td>数学模型</td><td>$z=\\boldsymbol{w}^{\\top}\\boldsymbol{x}+b$，阶跃输出</td><td>几何意义：超平面分类</td><td>⭐⭐</td></tr><tr><td>学习规则</td><td>错误才更新；收敛条件：线性可分</td><td>$w \\leftarrow w + \\eta(y-\\hat{y})x$</td><td>⭐⭐</td></tr><tr><td>XOR 局限</td><td>单层无法分类 XOR</td><td>原因：仅能学线性边界</td><td>⭐⭐⭐</td></tr><tr><td>多层感知机</td><td>加隐藏层 + 非线性激活 = 解决非线性</td><td>万能近似定理</td><td>⭐⭐⭐</td></tr></tbody></table>`,49)]))}const $=a(s,[["render",n]]);export{c as __pageData,$ as default};
